function doneFetch(e){Object.keys(e).forEach(l=>{l.startsWith("_")||(e[l].level&&-1!==e[l].level?divisions[e[l].level-1].clubs[l]=e[l]:e[l].level&&-1===e[l].level&&(divisions[divisions.length-1].clubs[l]=e[l]))}),divisions.forEach(e=>{divHeader=document.createElement("H2"),divHeader.innerHTML=e.name,dataContainer.append(divHeader),divClubs=document.createElement("UL"),divClubs.id="seasonlist",divClubs.classList.add("no-margin"),Object.keys(e.clubs).sort((l,n)=>e.clubs[l].name.localeCompare(e.clubs[n].name)).forEach(l=>{clubLi=document.createElement("LI"),clubLink=document.createElement("A"),clubLink.innerHTML=e.clubs[l].name,clubLink.setAttribute("href","club.html?club="+l),clubLi.append(clubLink),divClubs.append(clubLi)}),dataContainer.append(divClubs)})}